# Chaining Conditions

```python
if condition1:
    # If condition1 is True
elif condition2:
    # If condition1 False, condition2 True
elif condition3:
    # If both above False, condition3 True
else:
    # If ALL conditions are False
```

slides.codeSnippet:
score = 85

if score >= 90:
    grade = "A"
elif score >= 80:
    grade = "B"
elif score >= 70:
    grade = "C"
elif score >= 60:
    grade = "D"
else:
    grade = "F"

print(f"Score: {score} → Grade: {grade}")

hour = 14  # 24-hour format

if hour < 12:
    greeting = "Good morning!"
elif hour < 17:
    greeting = "Good afternoon!"
elif hour < 21:
    greeting = "Good evening!"
else:
    greeting = "Good night!"

print(f"It's {hour}:00 - {greeting}")

command = "start"

if command == "start":
    print("Starting...")
elif command == "stop":
    print("Stopping...")
elif command == "restart":
    print("Restarting...")

# Unknown commands are silently ignored
print("Command processed.")

